    lookahead1W(165);               // Identifier | IntegerConstant | FloatingConstant | CharacterConstant |
                                    // StringLiteral | WhiteSpace | '!' | '&' | '(' | ')' | '*' | '+' | '++' | ',' |
                                    // '-' | '--' | ':' | '::' | ';' | '>' | ']' | 'const_cast' | 'delete' |
                                    // 'dynamic_cast' | 'false' | 'new' | 'operator' | 'reinterpret_cast' | 'sizeof' |
                                    // 'static_cast' | 'this' | 'throw' | 'true' | 'typeid' | '}' | '~'
